import requests
import json
from botocore.vendored import requests

def lambda_handler(event, context):
    
    # Get the request from the event
    request = event['Records'][0]['cf']['request']

    # Get the X-Enrich-URL from the headers
    x_enrich_url_header = request['headers'].get('x-enrich-url', [{}])[0].get('value')

    # If there is X-Enrich-URL presented in header
    if x_enrich_url_header:
        try:
            # Fetch additional data from the URL
            response_url = requests.get(x_enrich_url_header)

            # if HTTP request is successful
            if response_url.status_code == 200:

                # Parse the response
                context_data = response_url.json()

                # Add the context data to the request headers
                request['headers']['x-enrich-context-data'] = [{'key':'x-enrich-context-data', 'value': json.dumps(context_data)}]
        except:
            # logging exception message would be done here
            pass

    # Return the request back to CloudFront
    return request